-title{font-size:32px}.pp-card{padding:32px}.pp-card-header{flex-direction:column;gap:16px}.pp-card-features{grid-template-columns:1fr}.integration-orbit{width:280px;height:280px}.integration-hub{width:100px;height:100px}.integration-hub-icon{width:36px;height:36px}.integration-node{width:75px;height:75px;border-radius:16px}.integration-node-icon{width:36px;height:36px;margin-bottom:6px}.integration-node-name{font-size:11px}.integration-node--erp{top:-25px}.integration-node--wms{bottom:-25px}.integration-node--mes{right:-25px}.integration-node--aiot{left:-25px}.integration-diagram{min-height:400px;padding:60px 0}.integration-message{padding:32px 24px}.products-cta-title{font-size:28px}.products-cta-buttons{flex-direction:column}.btn-white, .btn-outline-white{width:100%;text-align:center;justify-content:center}} */\n\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n\n.et_pb_section .product-card {\n            line-height: 25.6px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .product-card-link {\n            line-height: 22.4px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n/* === SECTION === */\n.et_pb_section:has(.elec-faq){padding:60px 0 !important;background:#f8fafc !important}\n.elec-faq{-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.elec-faq p{padding-bottom:0;line-height:1.6}\n.et_pb_section .elec-faq h2{margin:0;padding:0;line-height:1.6}\n.elec-faq summary{-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){}\n/* === CTA: MASTER ELECTRONICS COMPLEXITY === */\n.elec-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.elec-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.elec-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.elec-cta-super-d{position:absolute;top:50%;right:auto;left:50%;width:80%;min-height:80vh;background:url("data:image/svg+xml;base64,") no-repeat center center;background-size:contain;transform:translate(-50%, -50%);opacity:0.1;pointer-events:none;z-index:0}\n.elec-cta-wave-flow{position:absolute;bottom:0;left:0;right:0;height:170px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.15));opacity:0.08;z-index:1;pointer-events:none}\n.elec-cta-container{position:relative;z-index:3;max-width:700px;margin:0 auto;text-align:center}\n.elec-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.elec-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .elec-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .elec-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .elec-cta-container p{padding-bottom:0 !important}\n\n.elec-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.elec-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;