n.elec-related-card-title{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px 0;padding:0;line-height:1.6;-webkit-font-smoothing:auto}\n.elec-related-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666;margin:0;padding:0;line-height:1.5;-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){.elec-related-card{transition:none}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Elec Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Elec Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Elec Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><style>\n.elec-hero{background:linear-gradient(135deg,#000432 0%,#000864 50%,#001080 100%)!important;padding:140px 0 100px;position:relative;overflow:hidden}\n.elec-hero::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%233798E4\' fill-opacity=\'0.06\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");opacity:0.5}\n.elec-hero-inner{max-width:1200px;margin:0 auto;padding:0 24px;position:relative;z-index:1;text-align:center}\n.elec-hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(0,175,240,0.2);border:1px solid rgba(0,175,240,0.3);padding:8px 20px;border-radius:50px;color:#7EC8F2;font-size:14px;font-weight:500;margin-bottom:24px}\n.elec-hero h1{font-family:\'Noto Sans\',sans-serif!important;font-size:52px!important;font-weight:700!important;color:#fff!important;margin-bottom:20px;line-height:1.15!important}\n.elec-hero h1 span{color:#00AFF0!important}\n.elec-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px!important;color:rgba(255,255,255,0.85)!important;max-width:700px;margin:0 auto 50px;line-height:32px!important}\n.elec-hero-stats{display:flex;justify-content:center;gap:60px}\n.elec-hero-stat{text-align:center}\n.elec-hero-stat-value{font-family:\'Noto Sans\',sans-serif;font-size:42px;font-weight:700;color:#00AFF0!important;line-height:67.2px!important}\n.elec-hero-stat-label{font-size:14px;color:rgba(255,255,255,0.85);margin-top:4px!important;line-height:22.4px!important}\n@media(max-width:1024px){.elec-hero h1{font-size:40px!important}.elec-hero-stats{gap:40px}}\n@media(max-width:640px){.elec-hero{padding:120px 0 80px}.elec-hero h1{font-size:32px!important}.elec-hero-subtitle{font-size:17px!important}.elec-hero-stats{flex-direction:column;gap:24px}.elec-hero-stat-value{font-size:36px}}\n</style>\n    <div class="elec-hero">\n    <div class="dw-d-bg dw-d-bg--top" style="opacity: 0.12;"></div>\n            <div class="elec-hero-inner" style="position: relative; z-index: 2;">\n                <div class="elec-hero-badge">\n                    <span>Electronics Assembly</span>\n                </div>\n                <h1>Precision for <span>High-Mix</span> Manufacturing</h1>\n                <p class="elec-hero-subtitle">Thousands of components per board. Fast product cycles. Complete traceability. Built specifically for electronics complexity.</p>\n                <div class="elec-hero-stats">\n                    <div class="elec-hero-stat">\n                        <div class="elec-hero-stat-value">1000+</div>\n                        <div class="elec-hero-stat-label">Component types tracked</div>\n                    </div>\n                    <div class="elec-hero-stat">\n                        <div class="elec-hero-stat-value">99.9%</div>\n                        <div class="elec-hero-stat-label">Pick accuracy</div>\n                    </div>\n                    <div class="elec-hero-stat">\n                        <div class="elec-hero-stat-value">-45%</div>\n                        <div class="elec-hero-stat-label">MSD scrap reduction</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="context-section">\n    <div class="context-inner">\n                <h2>Thailand\'s Electronics Ecosystem</h2>\n                <p>Thailand exports <strong>$40+ billion in electronics annually</strong>, from hard disk drives to automotive electronics to consumer devices. Electronics manufacturers face unique complexity: <strong>hundreds of unique parts per product</strong>, constant changeovers for high-mix production, and moisture-sensitive components that require precise handling. DigiWin\'s MES was built specifically for this challenge.</p>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="challenges-section">\n    <div class="dw-wave-vertical--right" style="opacity: 0.06;"></div>\n            <div class="challenges-inner" style="position: relative; z-index: 2;">\n                <div class="challenges-header">\n                    <h2>The Electronics Manufacturing Challenge</h2>\n                    <p>Complexity that generic systems can\'t handle</p>\n                </div>\n                <div class="challenges-grid">\n                    <div class="challenge-card">\n                        <div class="challenge-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>\n                        </div>\n                        <h3>Component Chaos</h3>\n                        <p>Hundreds of unique parts per product. Thousands of reels in inventory. One wrong component placed = entire batch scrap.</p>\n                    </div>\n                    <div class="challenge-card">\n                        <div class="challenge-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n                        </div>\n                        <h3>Fast Changeovers</h3>\n                        <p>High-mix, low-volume means constant changeovers. Every minute of setup time is lost production capacity you can\'t recover.</p>\n                    </div>\n                    <div class="challenge-card">\n                        <div class="challenge-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v6l3-3"/><path d="M12 8l-3-3"/><path d="M12 22v-6l3 3"/><path d="M12 16l-3 3"/><path d="M2 12h6l-3 3"/><path d="M8 12l-3-3"/><path d="M22 12h-6l3 3"/><path d="M16 12l3-3"/></svg>\n                        </div>\n                        <h3>Moisture Sensitivity</h3>\n                        <p>MSD components that expire after floor exposure. Track it or scrap it. Manual tracking simply can\'t keep up with the pace.</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="solutions-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <line x1="200" y1="0" x2="200" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="400" y1="0" x2="400" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="600" y1="0" x2="600" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="800" y1="0" x2="800" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="1000" y1="0" x2="1000" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="1200" y1="0" x2="1200" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <path d="M200 300 L400 300 L400 500 L600 500" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <path d="M800 200 L1000 200 L1000 400 L1200 400" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <path d="M200 600 L400 600 L400 700 L800 700" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <circle cx="200" cy="300" r="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/>\n                    <circle cx="400" cy="300" r="4" fill="#000864" opacity="0.12"/>\n                    <circle cx="400" cy="500" r="4" fill="#000864" opacity="0.12"/>\n                    <circle cx="600" cy="500" r="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/>\n                    <circle cx="800" cy="200" r="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/>\n                    <circle cx="1000" cy="200" r="4" fill="#000864" opacity="0.12"/>\n                    <circle cx="1000" cy="400" r="4" fill="#000864" opacity="0.12"/>\n                    <circle cx="1200" cy="400" r="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/>\n                    <rect x="550" y="250" width="60" height="40" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <rect x="900" y="550" width="60" height="40" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <rect x="300" y="400" width="40" height="25" rx="2" stroke="#000864" stroke-width="1" fill="none" opacity="0.1"/>\n                    <rect x="1050" y="300" width="40" height="25" rx="2" stroke="#000864" stroke-width="1" fill="none" opacity="0.1"/>\n                    <circle cx="700" cy="350" r="3" fill="#00AFF0" opacity="0.12"/>\n                    <circle cx="1100" cy="650" r="4" fill="#000864" opacity="0.06"/>\n                </svg>\n            </div>\n            <div class="solutions-inner" style="position: relative; z-index: 2;">\n                <div class="solutions-header">\n                    <h2>How DigiWin Solves It</h2>\n                    <p>Purpose-built capabilities for electronics assembly</p>\n                </div>\n                <div class="solutions-grid">\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg>\n                        </div>\n                        <h3>SMT Machine Integration</h3>\n                        <p>Direct connection to pick-and-place machines. Verify component reels before mounting. Prevent wrong-part defects at the source.</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Reel verification at feeder</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Wrong-part prevention</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Program download automation</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M20.59 13.41l-7.17 7.17a2 2 0 0 1-2.83 0L2 12V2h10l8.59 8.59a2 2 0 0 1 0 2.82z"/><line x1="7" y1="7" x2="7.01" y2="7"/></svg>\n                        </div>\n                        <h3>Component-Level Traceability</h3>\n                        <p>Track every reel to every board position. Know exactly which components went into which products.</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Reel to serial number linkage</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Full forward/backward trace</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Recall scope minimization</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2.69l5.66 5.66a8 8 0 1 1-11.31 0z"/></svg>\n                        </div>\n                        <h3>MSD Management</h3>\n                        <p>Automatic floor life tracking for moisture-sensitive components. System alerts before expiry to reduce scrap.</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Auto floor life countdown</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Bake-out cycle tracking</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Expiry alerts & blocking</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/></svg>\n                        </div>\n                        <h3>AOI/ICT Integration</h3>\n                        <p>Connect inspection results to MES. Track defect trends by component, machine, operator, and time.</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Auto defect capture</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Pareto analysis</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>SPC trending</span>\n                            </div>\n                        </div>\n                    </div>\n    \n                    <div class="solution-card" style="border: 2px solid rgba(0,175,240,0.3); background: linear-gradient(135deg, rgba(0,175,240,0.03), rgba(255,255,255,1));">\n                        <div class="solution-icon" style="background: linear-gradient(135deg, rgba(0,175,240,0.2), rgba(0,175,240,0.1));">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/><path d="M9 12l2 2 4-4"/></svg>\n                        </div>\n                        <h3>BOI Compliance</h3>\n                        <p>Production-order-level material reconciliation for BOI audits. Track actual component consumption per assembly order — critical for bonded electronic components.</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>BOI-ready audit reports</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Bonded component tracking</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Proven: 10M+ THB/yr saved</span>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Equipment"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Equipment: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Equipment: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="equipment-section">\n    <div class="equipment-inner" style="position: relative; z-index: 2;">\n                <h3>Direct Equipment Integration</h3>\n                <p style="font-family: \'Noto Sans\', sans-serif; font-size: 16px; color: #666; max-width: 700px; margin: 0 auto 40px; line-height: 1.6;">DigiWin MES connects directly to your SMT lines, inspection stations, reflow ovens, and test equipment — capturing real-time production data without manual entry.</p>\n    \n                \n                <div style="margin-bottom: 32px;">\n                    <span style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; font-weight: 500; text-transform: uppercase; letter-spacing: 0.1em; color: #00AFF0; display: block; margin-bottom: 12px;">SMT Pick-and-Place</span>\n                    <div class="equipment-logos">\n                        <div class="equipment-logo">Fuji</div>\n                        <div class="equipment-logo">Panasonic</div>\n                        <div class="equipment-logo">Yamaha</div>\n                        <div class="equipment-logo">Juki</div>\n                        <div class="equipment-logo">ASM</div>\n                    </div>\n                </div>\n    \n                \n                <div style="margin-bottom: 32px;">\n                    <span style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; font-weight: 500; text-transform: uppercase; letter-spacing: 0.1em; color: #00AFF0; display: block; margin-bottom: 12px;">AOI & Inspection</span>\n                    <div class="equipment-logos">\n                        <div class="equipment-logo">Koh Young</div>\n                        <div class="equipment-logo">Saki</div>\n                        <div class="equipment-logo">Omron</div>\n                    </div>\n                </div>\n    \n                \n                <div>\n                    <span style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; font-weight: 500; text-transform: uppercase; letter-spacing: 0.1em; color: #00AFF0; display: block; margin-bottom: 12px;">Reflow Ovens & Test</span>\n                    <div class="equipment-logos">\n                        <div class="equipment-logo">Heller</div>\n                        <div class="equipment-logo">BTU</div>\n                        <div class="equipment-logo">Keysight</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Fade In"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Fade In: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Fade In: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="fade-in">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n                <div style="background: linear-gradient(135deg, rgba(0,175,240,0.04), rgba(0,8,100,0.04)); border: 1px solid rgba(0,175,240,0.2); border-left: 4px solid #00AFF0; border-radius: 12px; padding: 40px 40px 36px;">\n                    <span style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; font-weight: 500; text-transform: uppercase; letter-spacing: 0.1em; color: #00AFF0; display: block; margin-bottom: 8px;">DigiWin in Thai Electronics</span>\n                    <h3 style="font-family: \'Noto Sans\', sans-serif; font-size: 24px; font-weight: 700; color: #000864; margin: 0 0 16px;">Hoo Chin Electronics (Thailand)</h3>\n                    <p style="font-family: \'Noto Sans\', sans-serif; font-size: 16px; line-height: 1.7; color: #333; margin: 0 0 20px;">Hoo Chin Electronics, a Thai electronics manufacturer and one of DigiWin\'s local clients, chose DigiWin ERP to manage the complexity of high-mix production, BOI compliance, and multi-material component tracking — the same challenges your factory faces every day.</p>\n                    <p style="font-family: \'Noto Sans\', sans-serif; font-size: 14px; line-height: 1.6; color: #666; margin: 0;">This is not just an Asia-wide reference. Hoo Chin operates in Thailand, navigates Thai regulations, and works with Thai supply chains — proof that DigiWin delivers results in your market.</p>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="products-section">\n    <div class="products-inner">\n                <div class="products-header">\n                    <h2>Recommended Products for Electronics</h2>\n                </div>\n                <div class="products-grid">\n                    <a href="../products/mes/" class="product-card">\n                        <div class="product-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M6 7V5a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v2"/><circle cx="6" cy="12" r="1"/><circle cx="10" cy="12" r="1"/><circle cx="14" cy="12" r="1"/><circle cx="18" cy="12" r="1"/></svg>\n                        </div>\n                        <h3>MES</h3>\n                        <p>Component-level traceability, SMT integration, MSD management, and real-time quality tracking for electronics.</p>\n                        <span class="product-card-link">Learn More <span>→</span></span>\n                    </a>\n                    <a href="../products/wms/" class="product-card">\n                        <div class="product-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.29 7 12 12 20.71 7"/><line x1="12" y1="22" x2="12" y2="12"/></svg>\n                        </div>\n                        <h3>sFLS WMS</h3>\n                        <p>Reel management, moisture-sensitive handling, and kitting support for electronics warehouse operations.</p>\n                        <span class="product-card-link">Learn More <span>→</span></span>\n                    </a>\n                    <a href="../products/aiot/" class="product-card">\n                        <div class="product-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v4m0 12v4M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M2 12h4m12 0h4M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83"/><circle cx="12" cy="12" r="3"/></svg>\n                        </div>\n                        <h3>AIoT</h3>\n                        <p>Machine connectivity for SMT lines, reflow ovens, and test equipment. Real-time OEE and process monitoring.</p>\n                        <span class="product-card-link">Learn More <span>→</span></span>\n                    </a>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="elec-faq">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n            <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px; text-align: center;">Frequently Asked Questions</h2>\n            <div style="display: flex; flex-direction: column; gap: 12px;">\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What MES system works best for electronics assembly in Thailand?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin MES is purpose-built for the complexity of electronics assembly, with native SMT machine integration that generic MES platforms cannot match. The system handles high-mix, low-volume production with thousands of unique component types, tracking every reel to every board position. It is deployed across Thailand\'s electronics ecosystem, which exports over $40 billion in electronics annually, from hard disk drives to automotive electronics.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">Can DigiWin MES integrate with Fuji and Panasonic SMT machines?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Yes. DigiWin provides direct machine connectivity with all major SMT equipment brands including Fuji, Panasonic, Yamaha, Juki, and ASM pick-and-place machines, as well as AOI and ICT inspection systems from Koh Young, Omron, and Keysight. This integration enables reel verification at the feeder, wrong-part prevention, and automated program downloads, eliminating the manual data entry that causes costly component placement errors.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">How does DigiWin handle moisture-sensitive component (MSD) tracking?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin automates the entire floor-life management process for moisture-sensitive devices. The system starts an automatic countdown the moment an MSD package is opened and exposed to floor conditions, tracks bake-out cycles for components that need reconditioning, and sends expiry alerts that block expired components from being used on the line. This automated approach has achieved a 45% reduction in MSD-related scrap compared to manual tracking methods.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">Does DigiWin support BOI compliance for electronics factories?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Yes. DigiWin provides production-order-level material reconciliation specifically designed for BOI audits in electronics manufacturing. The system tracks actual component consumption per assembly order, which is critical for bonded electronic components that require precise import duty reconciliation. Electronics factories using DigiWin for BOI compliance have reported savings of over 10 million THB per year through accurate duty drawback claims and BOI-ready audit reports.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What pick accuracy can I achieve with DigiWin WMS?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin sFLS WMS delivers 99.9% pick accuracy for electronics warehouse operations. The system manages reel-level inventory with precise moisture-sensitive component handling, automated kitting support for production orders, and barcode-driven verification at every step. For electronics factories managing hundreds of unique parts per product and thousands of reels in inventory, this level of accuracy prevents the costly errors where one wrong component placed can result in an entire batch being scrapped.</p>\n                </div>\n              </details>\n            </div>\n          </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Master Electronics Complexity"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Master Electronics Complexity: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Master Electronics Complexity: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="elec-cta-section">\n    <div class="elec-cta-super-d" aria-hidden="true"></div>\n    <div class="elec-cta-wave-flow" aria-hidden="true"></div>\n    <div class="elec-cta-container">\n      <h2 class="elec-cta-title">Master Electronics Complexity</h2>\n      <p class="elec-cta-subtitle">See how DigiWin handles high-mix manufacturing</p>\n      <div class="elec-cta-btn-row">\n        <a href="/demo/" class="elec-cta-btn elec-cta-btn--primary">Get in Touch</a>\n        <a href="/industries/" class="elec-cta-btn elec-cta-btn--ghost">View Other Industries</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:html --><style>\n.elec-related-grid{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(280px,1fr))!important;gap:24px!important;max-width:1200px!important;margin:0 auto!important}\n.elec-related-card{display:block!important;padding:24px!important;background:#fff!important;border-radius:12px!important;text-decoration:none!important;border:1px solid #e5e7eb!important;color:#333!important;line-height:1.6!important}\n.elec-related-card-title{font-size:18px!important;font-weight:600!important;color:#000864!important;margin:0 0 8px 0!important}\n.elec-related-card-desc{font-size:14px!important;color:#666!important;margin:0!important}\n</style><div class="elec-related-section">\n    <h2 class="elec-related-heading">Explore Related Solutions</h2>\n    <div class="elec-related-grid">\n      <a href="/industries/automotive/" class="elec-related-card">\n        <h3 class="elec-related-card-title">Automotive</h3>\n        <p class="elec-related-card-desc">ERP and MES solutions purpose-built for automotive parts manufacturers and OEM suppliers.</p>\n      </a>\n      <a href="/industries/metal-plastics/" class="elec-related-card">\n        <h3 class="elec-related-card-title">Metal &amp; Plastics</h3>\n        <p class="elec-related-card-desc">Integrated solutions for die casting, injection molding, and metal fabrication shops.</p>\n      </a>\n      <a href="/products/erp/" class="elec-related-card">\n        <h3 class="elec-related-card-title">ERP</h3>\n        <p class="elec-related-card-desc">End-to-end manufacturing ERP built for Thai factories — from BOM to financials to BOI compliance.</p>\n      </a>\n      <a href="/products/mes/" class="elec-related-card">\n        <h3 class="elec-related-card-title">MES</h3>\n        <p class="elec-related-card-desc">Real-time shop floor execution system — OEE tracking, SPC, and paperless work orders.</p>\n      </a>\n      <a href="/products/wms/" class="elec-related-card">\n        <h3 class="elec-related-card-title">WMS</h3>\n        <p class="elec-related-card-desc">Smart warehouse management with barcode/RFID — from receiving to dispatch with full traceability.</p>\n      </a>\n      <a href="/products/aiot/" class="elec-related-card">\n        <h3 class="elec-related-card-title">AIoT</h3>\n        <p class="elec-related-card-desc">Connect machines directly to your ERP with IoT sensors, edge computing, and AI-powered analytics.</p>\n      </a>\n    </div>\n  </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100566;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100566 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100566, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === ELEC HERO (S1) === */\n/* TODO: Review and remap class selectors to use eleh prefix */\n/* TODO: Add section container: .eleh-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n/* TODO: PSEUDO-ELEMENTS using global classes (port manually) */\n.auto-hero::before, .elec-hero::before, .metal-hero::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%233798E4\' fill-opacity=\'0.06\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");opacity:0.5}\n.auto-hero, .elec-hero, .metal-hero{background:linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);padding:140px 0 100px;position:relative;overflow:hidden}\n.auto-hero-inner, .elec-hero-inner, .metal-hero-inner{max-width:1200px;margin:0 auto;padding:0 24px;position:relative;z-index:1;text-align:center}\n.auto-hero-badge, .elec-hero-badge, .metal-hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(0, 175, 240, 0.2);border:1px solid rgba(0, 175, 240, 0.3);padding:8px 20px;border-radius:50px;color:#7EC8F2;font-size:14px;font-weight:500;margin-bottom:24px}\n.auto-hero h1, .elec-hero h1, .metal-hero h1{font-family:\'Noto Sans\', sans-serif;font-size:52px;font-weight:700;color:#fff;margin-bottom:20px;line-height:1.15}\n.auto-hero h1 span, .elec-hero h1 span, .metal-hero h1 span{color:#00AFF0}\n.elec-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.85);max-width:700px;margin:0 auto 50px;line-height:1.6}\n.elec-hero-stats{display:flex;justify-content:center;gap:60px}\n.elec-hero-stat{text-align:center}\n.elec-hero-stat-value{font-family:\'Noto Sans\',sans-serif;font-size:42px;font-weight:700;color:#00AFF0}\n.elec-hero-stat-label{font-size:14px;color:rgba(255,255,255,0.85);margin-top:4px}\n@media (max-width:1024px){.auto-hero h1, .elec-hero h1, .metal-hero h1{font-size:40px}.auto-hero-stats, .elec-hero-stats, .metal-hero-stats{gap:40px}.stakes-grid, .challenges-grid{grid-template-columns:1fr}.solutions-grid{grid-template-columns:1fr}.products-grid{grid-template-columns:1fr}}\n@media (max-width:640px){.auto-hero, .elec-hero, .metal-hero{padding:120px 0 80px}.auto-hero h1, .elec-hero h1, .metal-hero h1{font-size:32px}.auto-hero-subtitle, .elec-hero-subtitle, .metal-hero-subtitle{font-size:17px}.auto-hero-stats, .elec-hero-stats, .metal-hero-stats{flex-direction:column;gap:24px}.auto-hero-stat-value, .elec-hero-stat-value, .metal-hero-stat-value{font-size:36px}.stake-card, .challenge-card{padding:32px 24px}.solution-card{padding:32px}.cta-section h2{font-size:28px}.cta-buttons{flex-direction:column}}\n/* @media (prefers-reduced-motion:reduce){.products-hero-content,.hero-stack-visual,.products-hero::before,.products-hero-badge::before,.stack-layer,.stack-layer::before,.data-particle,.ecosystem-node,.ecosystem-line,.ecosystem-ring,.data-flow-line,.data-flow-dot,.integration-hub::before,.integration-hub::after,.pp-card,.why-card,.why-card-icon,.pp-card-icon,.products-cta-glow,.dw-d-parallax,.dw-wave-flow,.dw-d-bg{animation:none !important;transition:none !important}.pp-card.visible{opacity:1;transform:none}} */\n\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:-20%;right:-10%;bottom:auto;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center top;background-size:contain;opacity:0.12;pointer-events:none;z-index:0}\n\n/* Divi overrides */\n.et_pb_section .elec-hero h1{font-weight:700 !important;line-height:1.15 !important}\n.et_pb_section .elec-hero-subtitle{line-height:32px !important;-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n.et_pb_section .elec-hero-stat-value {\n            line-height: 67.2px !important;\n        \n            color: rgb(0, 175, 240) !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .elec-hero-stat-label {\n            line-height: 22.4px !important;\n        \n            margin-top: 4px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n/* === CONTEXT (S2) === */\n/* TODO: Review and remap class selectors to use con prefix */\n/* TODO: Add section container: .context-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n@media (prefers-reduced-motion:reduce){.fade-in{opacity:1;transform:none;transition:none}}\n.context-section{padding:100px 0;background:#fff}\n.context-inner{max-width:900px;margin:0 auto;padding:0 24px;text-align:center}\n.context-inner h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:24px}\n.context-inner p{font-size:18px;color:#5b6b80;line-height:1.8}\n.context-inner p strong{color:#000864}\n/* Divi overrides */\n.et_pb_section .context-inner h2{font-weight:700 !important;line-height:1.6 !important}\n.et_pb_section .context-inner p{padding-bottom:0 !important;line-height:1.8 !important}\n\n@media(prefers-reduced-motion:reduce){}\n/* === CHALLENGES (S3) === */\n/* TODO: Review and remap class selectors to use cha prefix */\n/* TODO: Add section container: .challenges-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n/* TODO: HOVER STATES using global classes (port manually) */\n/* .stake-card:hover .stake-icon, .challenge-card:hover .challenge-icon{background:linear-gradient(135deg, #00AFF0, #003CC8)} */\n/* .stake-card:hover .stake-icon svg, .challenge-card:hover .challenge-icon svg{stroke:#fff} */\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n@media (prefers-reduced-motion:reduce){.fade-in{opacity:1;transform:none;transition:none}}\n.stakes-section, .challenges-section{padding:100px 0;background:#F5F7FA}\n.stakes-inner, .challenges-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.stakes-header, .challenges-header{text-align:center;margin-bottom:60px}\n.stakes-header h2, .challenges-header h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:16px}\n.stakes-header p, .challenges-header p{font-size:18px;color:#5b6b80}\n.challenges-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:32px}\n.challenge-card{background:linear-gradient(145deg,#fef2f2 0%,#fee2e2 100%);border:1px solid #fecaca;border-radius:20px;padding:40px 32px;text-align:center}\n.challenge-icon{width:72px;height:72px;background:linear-gradient(135deg,#fee2e2,#fecaca);border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 24px;transition:all 0.4s ease}\n.challenge-icon svg{width:32px;height:32px;stroke:#b91c1c;stroke-width:1.5;fill:none}\n.challenge-card h3{font-family:\'Noto Sans\',sans-serif;font-size:22px;color:#991b1b;margin-bottom:16px}\n.challenge-card p{font-size:15px;color:#b91c1c;line-height:1.7}\n.challenge-card:hover .challenge-icon{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.challenge-card:hover .challenge-icon svg{stroke:#fff}\n/* Divi overrides */\n.et_pb_section .challenges-header h2{font-weight:700 !important;line-height:1.6 !important}\n.et_pb_section .challenge-card h3{line-height:35.2px !important}\n.et_pb_section .challenge-card p{line-height:25.5px !important;padding-bottom:0 !important}\n@media(max-width:1024px){.challenges-grid{grid-template-columns:1fr}}\n@media(max-width:640px){.challenge-card{padding:32px 24px}}\n\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n/* === SOLUTIONS (S4) === */\n.solutions-section{padding:100px 0;background:#fff;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.dw-section-scene{position:absolute;inset:0;pointer-events:none;z-index:0}\n.dw-section-scene svg{width:100%;height:100%;position:absolute;top:0;left:0}\n.solutions-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.solutions-header{text-align:center;margin-bottom:60px}\n.solutions-header h2{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.solutions-header p{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n.solutions-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:32px}\n.solution-card{background:#fff;border:1px solid #e2e8f0;border-radius:20px;padding:40px;transition:all 0.3s ease}\n.solution-card:hover{border-color:#00AFF0;box-shadow:0 12px 40px rgba(0,175,240,0.12)}\n.solution-icon{width:64px;height:64px;background:linear-gradient(135deg,rgba(0,175,240,0.15),rgba(0,175,240,0.05));border-radius:16px;display:flex;align-items:center;justify-content:center;margin-bottom:24px;transition:all 0.4s ease}\n.solution-icon svg{width:28px;height:28px;stroke:#00AFF0;stroke-width:1.5;fill:none}\n.solution-card:hover .solution-icon{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.solution-card:hover .solution-icon svg{stroke:#fff}\n.solution-card h3{font-family:\'Noto Sans\',sans-serif;font-size:22px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 12px;padding:0}\n.solution-card>p{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#5b6b80;line-height:1.7;margin:0 0 20px;padding:0}\n.solution-features{display:flex;flex-direction:column;gap:10px}\n.solution-feature{display:flex;align-items:center;gap:10px;font-size:14px;color:#475569}\n.solution-feature svg{width:18px;height:18px;color:#00AFF0;flex-shrink:0}\n@media(max-width:1024px){\n  .solutions-grid{grid-template-columns:1fr}\n}\n@media(max-width:768px){\n  .solutions-section{padding:80px 0}\n  .solution-card{padding:32px}\n}\n@media(prefers-reduced-motion:reduce){.solution-card{transition:none !important}.solution-icon{transition:none !important}}\n/* Divi line-height overrides */\n.et_pb_section .solutions-header h2{line-height:57.6px !important}\n.et_pb_section .solutions-header p{line-height:28.8px !important}\n.et_pb_section .solution-card h3{line-height:35.2px !important}\n.et_pb_section .solution-card>p{line-height:25.5px !important}\n.et_pb_section .solution-feature span{line-height:22.4px !important}\n/* === EQUIPMENT (S5) === */\n/* TODO: Review and remap class selectors to use equ prefix */\n/* TODO: Add section container: .equipment-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n@media (prefers-reduced-motion:reduce){.fade-in{opacity:1;transform:none;transition:none}}\n.oem-section, .equipment-section, .processes-section{padding:80px 0;background:#F5F7FA}\n.oem-inner, .equipment-inner, .processes-inner{max-width:1000px;margin:0 auto;padding:0 24px;text-align:center}\n.oem-inner h3, .equipment-inner h3, .processes-inner h3{font-family:\'Noto Sans\', sans-serif;font-size:24px;color:#000864;margin-bottom:40px}\n.oem-logos, .equipment-logos, .processes-logos{display:flex;flex-wrap:wrap;justify-content:center;gap:24px}\n.oem-logo, .equipment-logo, .process-logo{background:#fff;border:1px solid #e2e8f0;border-radius:12px;padding:20px 32px;font-family:\'Noto Sans\', sans-serif;font-size:16px;font-weight:600;color:#475569}\n\n@media(prefers-reduced-motion:reduce){}\n\n.et_pb_section .equipment-logo {\n            line-height: 25.6px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n/* === FADE IN / CASE STUDY CALLOUT (S6) === */\n.fade-in{opacity:1;transform:none;padding:80px 0;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n/* Divi overrides for inline-styled elements */\n.et_pb_section .fade-in h3{line-height:38.4px !important;margin-bottom:16px !important}\n.et_pb_section .fade-in p{padding-bottom:0 !important}\n.et_pb_section .fade-in p:first-of-type{line-height:27.2px !important}\n.et_pb_section .fade-in p:last-of-type{line-height:22.4px !important}\n@media(prefers-reduced-motion:reduce){}\n/* === PRODUCTS (S7) === */\n/* TODO: Review and remap class selectors to use pro prefix */\n/* TODO: Add section container: .products-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n/* === PSEUDO-ELEMENTS (auto-ported from styles.css) === */\n.pro-grid-section::before{content:\'\';position:absolute;top:0;left:0;right:0;height:1px;background:linear-gradient(90deg, transparent, #00AFF0, transparent)}\n.products-section-label::before,.products-section-label::after{content:\'\';width:40px;height:1px;background:linear-gradient(90deg, transparent, #00AFF0)}\n.products-section-label::after{background:linear-gradient(90deg, #00AFF0, transparent)}\n/* TODO: HOVER STATES using global classes (port manually) */\n/* .product-card:hover{border-color:#00AFF0;transform:translateY(-4px);box-shadow:0 12px 40px rgba(0, 175, 240, 0.12)} */\n/* .product-card:hover .product-card-icon{background:linear-gradient(135deg, #00AFF0, #003CC8)} */\n/* .product-card:hover .product-card-icon svg{stroke:#fff} */\n/* .product-card:hover .product-card-link{gap:10px} */\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n@media (prefers-reduced-motion:reduce){.fade-in{opacity:1;transform:none;transition:none}}\n.products-section{padding:100px 0;background:#fff}\n.products-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.products-header{text-align:center;margin-bottom:60px}\n.products-header h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:16px}\n.products-grid{display:grid;grid-template-columns:repeat(3, 1fr);gap:24px}\n.product-card{background:#fff;border:2px solid #e2e8f0;border-radius:16px;padding:32px;text-decoration:none;transition:all 0.3s ease;display:block}\n.product-card-icon{width:56px;height:56px;background:linear-gradient(135deg,rgba(0,175,240,0.1),rgba(0,175,240,0.05));border-radius:14px;display:flex;align-items:center;justify-content:center;margin-bottom:20px;transition:all 0.4s ease}\n.product-card-icon svg{width:28px;height:28px;stroke:#00AFF0;stroke-width:1.5;fill:none}\n.product-card h3{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:#000864;margin-bottom:12px}\n.product-card p{font-size:14px;color:#5b6b80;line-height:1.6;margin-bottom:16px}\n.product-card-link{display:inline-flex;align-items:center;gap:6px;color:rgb(3, 105, 161) !important;font-family:\'Noto Sans\',sans-serif;font-weight:600;font-size:14px}\n.product-card:hover{border-color:#00AFF0;transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,175,240,0.12)}\n.product-card:hover .product-card-icon{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.product-card:hover .product-card-icon svg{stroke:#fff}\n.product-card:hover .product-card-link{gap:10px}\n/* Divi overrides */\n.et_pb_section .products-header h2{font-weight:700 !important;line-height:1.6 !important}\n.et_pb_section .product-card h3{line-height:32px !important}\n.et_pb_section .product-card p{padding-bottom:0 !important}\n@media (max-width:1024px){.auto-hero h1, .elec-hero h1, .metal-hero h1{font-size:40px}.auto-hero-stats, .elec-hero-stats, .metal-hero-stats{gap:40px}.stakes-grid, .challenges-grid{grid-template-columns:1fr}.solutions-grid{grid-template-columns:1fr}.products-grid{grid-template-columns:1fr}}\n/* .products-grid-section{padding:120px 0;background:linear-gradient(180deg, #f8fafc 0%, #ffffff 30%, #ffffff 70%, #f8fafc 100%);position:relative;overflow:hidden} */\n/* .products-grid-section .grid-pattern{position:absolute;top:0;left:0;right:0;bottom:0;background-image:radial-gradient(circle, rgba(0, 175, 240, 0.03) 1px, transparent 1px);background-size:30px 30px;pointer-events:none} */\n/* .products-section-header{max-width:700px;margin:0 auto 80px;text-align:center;position:relative;z-index:1} */\n/* .products-section-label{font-family:\'JetBrains Mono\', monospace;font-size:11px;font-weight:500;color:#00AFF0;text-transform:uppercase;letter-spacing:0.15em;margin-bottom:16px;display:flex;align-items:center;justify-content:center;gap:12px} */\n/* .products-section-title{font-family:\'Noto Sans\', sans-serif;font-size:44px;font-weight:700;color:#000864;margin:0 0 16px 0;letter-spacing:-0.02em} */\n/* .products-section-subtitle{font-family:\'Noto Sans\', sans-serif;font-size:18px;color:#5b6b80;line-height:1.6} */\n/* @media (max-width:640px){.products-hero{padding:120px 0 60px;min-height:auto}.products-hero h1{font-size:28px}.products-hero-stats{flex-direction:column;gap:20px;align-items:center}.products-hero-stat{text-align:center}.products-section-title,